#include "interface.h"

#include "simdutf.h"

#include <cstdint>
#include <string>

namespace {

static inline uint64_t fnv1a_utf16(const char16_t* data, size_t len) {
  uint64_t hash = 1469598103934665603ULL;
  for (size_t i = 0; i < len; ++i) {
    hash ^= static_cast<uint64_t>(data[i]);
    hash *= 1099511628211ULL;
  }
  return hash;
}

}  // namespace

uint64_t transcode_checksum(const std::string& input) {
  const size_t in_len = input.size();
  const size_t utf16_len = simdutf::utf16_length_from_utf8(input.data(), in_len);

  // Allocate exact output size and transcode directly into it.
  std::u16string out;
  out.resize(utf16_len);
  simdutf::convert_valid_utf8_to_utf16le(input.data(), in_len, out.data());

  return fnv1a_utf16(reinterpret_cast<const char16_t*>(out.data()), out.size());
}
